import org.jfree.chart.JFreeChart;
import org.jfree.chart.entity.*;
import org.jfree.chart.plot.*;
import org.jfree.data.category.CategoryDataset;
import java.awt.Color;
import java.util.HashMap;
import java.util.Iterator;
import javax.swing.event.ChangeEvent;
import javax.swing.event.ChangeListener;
import org.jfree.chart.title.TextTitle;
import org.jfree.ui.RectangleInsets;
import org.jfree.chart.labels.*;

public class MultiplePiePlot extends AbstractCategoryPlot implements CategoryPlot, Cloneable {

    public MultiplePiePlot() {
        super(new CategoryItemEntityCollection());
        this.dataArea = new RectangleInsets(5, 0, 0, 18);        
    }

    @Override
    public void setDataset(int index, CategoryDataset dataset){
        super.setDataset(index, dataset);
        if (!getDataset().equals(dataset)) {
             return;
        }
        PiePlot pi = new PiePlot(dataset);
        pi.setLabelLinkEnabled(true);
        pi.setLabelGenerator(new StandardPieSectionLabelGenerator("{0}: {@1}"));
        LegendState legendstate = new DefaultLegendState();
        pi.setLegendState(legendstate);
        Iterator iter = getDataset().getGroupKeys().iterator();
        int i=0;
        while (iter.hasNext()) {
           pi.setSectionPaint(i, Color.decode("#"+Integer.toHexString(((Integer)getDataset().getValue(iter.next(),1)).intValue()).substring(2)));
           i++;
        }
        ChartPanel chartpanel = new ChartPanel(new JFreeChart(pi), true);
        changeListeners = new ArrayList<>();
        chartpanel.addChangeListener(new ChangeListener() {
            @Override
            public void stateChanged(ChangeEvent e) {
                notifyListeners();
            }
        });
        super.setDataset(index, null);
        add(chartpanel);
    }
}

